import { NextResponse } from "next/server"
import Deal from "@/models/Deal"
import { connectDB } from "@/lib/db"
import { getRules } from "@/lib/rules/getRules"
import { evaluateDeal } from "@/lib/engines/dealEvaluator"

export async function POST(req: Request) {
  await connectDB()
  const body = await req.json()

  if (
    !body.address ||
    typeof body.purchasePrice !== "number" ||
    typeof body.arv !== "number" ||
    typeof body.profitPercent !== "number"
  ) {
    return NextResponse.json(
      { error: "Invalid deal payload" },
      { status: 400 }
    )
  }

  const deal = await Deal.create({
    address: body.address,
    purchasePrice: body.purchasePrice,
    arv: body.arv,
    profitPercent: body.profitPercent,
    status: body.status ?? "FAIL",

    // Phase 1 deterministic defaults
    comps: [],
    arvAdjustments: [],
    domThreshold: null,
    failureReasons: [],

    source: "MANUAL",
  })

  return NextResponse.json(deal)
}
